import{_ as t,o as l,c as r,a2 as e}from"./chunks/framework.BZO4qERu.js";const c=JSON.parse('{"title":"騎砍2 | 鐵人模式生存指南：一條命通關卡拉迪亞","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/ironman-survival.md","filePath":"bannerlord/ironman-survival.md"}'),i={name:"bannerlord/ironman-survival.md"};function h(d,a,o,n,u,s){return l(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="騎砍2-鐵人模式生存指南-一條命通關卡拉迪亞" tabindex="-1">騎砍2 | 鐵人模式生存指南：一條命通關卡拉迪亞 <a class="header-anchor" href="#騎砍2-鐵人模式生存指南-一條命通關卡拉迪亞" aria-label="Permalink to &quot;騎砍2 | 鐵人模式生存指南：一條命通關卡拉迪亞&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>鐵人模式 = 不能手動存檔 + 人物死了就沒了。這不是給新手玩的。但如果你覺得普通模式太簡單，這篇教你怎麼活下去。</p><hr><h2 id="一、鐵人模式規則" tabindex="-1">一、鐵人模式規則 <a class="header-anchor" href="#一、鐵人模式規則" aria-label="Permalink to &quot;一、鐵人模式規則&quot;">​</a></h2><ul><li>只有一個存檔，自動儲存</li><li>無法手動存檔讀檔（SL大法無效）</li><li>你在戰鬥中死亡 → 可以選擇繼續扮演繼承人，或遊戲結束</li><li>每個決定都是永久的</li></ul><hr><h2 id="二、心態調整" tabindex="-1">二、心態調整 <a class="header-anchor" href="#二、心態調整" aria-label="Permalink to &quot;二、心態調整&quot;">​</a></h2><table tabindex="0"><thead><tr><th>普通模式</th><th>鐵人模式</th></tr></thead><tbody><tr><td>輸了讀檔</td><td>輸了就輸了</td></tr><tr><td>隨便衝鋒</td><td>每一場戰鬥都要計算</td></tr><tr><td>俘虜隨便殺</td><td>俘虜是重要資產</td></tr><tr><td>錢花光沒差</td><td>錢花光 = 死</td></tr></tbody></table><hr><h2 id="三、生存法則" tabindex="-1">三、生存法則 <a class="header-anchor" href="#三、生存法則" aria-label="Permalink to &quot;三、生存法則&quot;">​</a></h2><h3 id="_3-1-永遠不要自己衝第一個" tabindex="-1">3.1 永遠不要自己衝第一個 <a class="header-anchor" href="#_3-1-永遠不要自己衝第一個" aria-label="Permalink to &quot;3.1 永遠不要自己衝第一個&quot;">​</a></h3><p>普通模式你可以騎馬衝進敵陣耍帥。鐵人模式你被砍下馬 = 死。讓小兵先上。</p><h3 id="_3-2-保守接戰" tabindex="-1">3.2 保守接戰 <a class="header-anchor" href="#_3-2-保守接戰" aria-label="Permalink to &quot;3.2 保守接戰&quot;">​</a></h3><ul><li>敵方兵力 &gt; 你的 80%：不要打</li><li>敵方有大量騎兵而你步兵不夠：不要打</li><li>地形對你不利：不要打</li><li>不確定能不能贏：不要打</li></ul><h3 id="_3-3-留退路" tabindex="-1">3.3 留退路 <a class="header-anchor" href="#_3-3-留退路" aria-label="Permalink to &quot;3.3 留退路&quot;">​</a></h3><ul><li>永遠留至少養兵 14 天的錢</li><li>永遠留一條逃跑路線（Tab 撤退）</li><li>被俘之前先跑，不要賭</li></ul><h3 id="_3-4-醫療優先" tabindex="-1">3.4 醫療優先 <a class="header-anchor" href="#_3-4-醫療優先" aria-label="Permalink to &quot;3.4 醫療優先&quot;">​</a></h3><ul><li>找醫者型夥伴當外科醫生</li><li>醫學技能直接影響戰鬥後多少人能活下來</li><li>傷兵恢復速度快 = 你的部隊永遠滿編</li></ul><hr><h2 id="四、鐵人模式專屬策略" tabindex="-1">四、鐵人模式專屬策略 <a class="header-anchor" href="#四、鐵人模式專屬策略" aria-label="Permalink to &quot;四、鐵人模式專屬策略&quot;">​</a></h2><h3 id="_4-1-龜到強為止" tabindex="-1">4.1 龜到強為止 <a class="header-anchor" href="#_4-1-龜到強為止" aria-label="Permalink to &quot;4.1 龜到強為止&quot;">​</a></h3><p>第一年不要加入任何國家。專心貿易賺錢、練兵等、開工廠。等你家族等級 3、有 100+ 精兵、50 萬存款，再考慮參戰。</p><h3 id="_4-2-選安全的出身" tabindex="-1">4.2 選安全的出身 <a class="header-anchor" href="#_4-2-選安全的出身" aria-label="Permalink to &quot;4.2 選安全的出身&quot;">​</a></h3><ul><li>文化：瓦蘭迪亞（背靠海，不易被夾攻）</li><li>出身：商人（起始錢多，不用冒險打劫匪）</li></ul><h3 id="_4-3-隨時準備接班人" tabindex="-1">4.3 隨時準備接班人 <a class="header-anchor" href="#_4-3-隨時準備接班人" aria-label="Permalink to &quot;4.3 隨時準備接班人&quot;">​</a></h3><ul><li>盡早結婚生子</li><li>確保孩子成年時你還沒死</li><li>家族成員多 = 死了一個還有備胎</li></ul><hr><h2 id="五、鐵人模式推薦-mod" tabindex="-1">五、鐵人模式推薦 MOD <a class="header-anchor" href="#五、鐵人模式推薦-mod" aria-label="Permalink to &quot;五、鐵人模式推薦 MOD&quot;">​</a></h2><table tabindex="0"><thead><tr><th>MOD</th><th>原因</th></tr></thead><tbody><tr><td>Diplomacy</td><td>避免不必要的戰爭</td></tr><tr><td>Improved Garrisons</td><td>自動防禦，不用你親自守城</td></tr><tr><td>RTS Camera</td><td>死了還能指揮部隊</td></tr></tbody></table><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./beginner-guide.html">騎砍2 | 新手求生指南</a></li><li><a href="./clan-family.html">騎砍2 | 家族與結婚系統</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',39)])])}const m=t(i,[["render",h]]);export{c as __pageData,m as default};
